var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"RITA_HORIZON_NULL_ON","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_ON","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"한 놈만 나타나서 다행이군. 하나 더 가세했으면 손 쓸 틈도 없이 당했겠어.","JPN":"1匹だけでよかった。もう1匹いたら打つ手もなくやられただろう。","ENG":"Thank goodness only one of them showed up. I wouldn't have stood a chance if there were any more.","TWN":"幸好只有一個傢伙。要是再加上一個，就一點辦法也沒有了。"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"언니! 수고하셨어요!","JPN":"リタお姉ちゃん！　お疲れ様でした！","ENG":"Rita! Great job!","TWN":"姐姐！辛苦了！"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"호들갑 떨기엔 아직 일러, 꼬맹이.","JPN":"その台詞はまだ早い、ガキ。","ENG":"It's still too early to get excited, kid.","TWN":"還早呢，小鬼。"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"갈 길이 머니까 체력을 아껴 둬. 지금은 네가......","JPN":"先が長いから体力を温存しておけ。今はお前が……","ENG":"Conserve your energy. We've got a long ways to go. Right now, you're...","TWN":"路還長，節省體力。現在你……"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":" 응?","JPN":"ん？","ENG":" Huh?","TWN":" 嗯？"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SPIRA_CORRUPT_NULL_DASH","text":{"KOREA":"왜 그래요, 언니?","JPN":"どうしました、リタお姉ちゃん？","ENG":"What's wrong, Rita?","TWN":"你怎麼了，姐姐？"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":{"char_id":"SPIRA_CORRUPT_NULL_DASH","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SPIRA_CORRUPT_NULL_DASH","text":{"KOREA":"여기 보세요. 이번에는 생채기 하나 안 났어요.","JPN":"ほら、見てください。今回は傷一つなしで倒せたんですよ。","ENG":"Look. I didn't get a single scratch this time.","TWN":"看我，這次一個傷痕都沒有。"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":{"char_id":"SPIRA_CORRUPT_NULL_DASH","face":"UNIT_LAUGH"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SPIRA_CORRUPT_NULL_DASH","text":{"KOREA":"헤헤, 저도 그새 실력이 쑥쑥 늘었나 봐요.","JPN":"へへ、私も実力がぐんぐん伸びてきたと思いませんか？","ENG":"Heh, I must have improved a lot.","TWN":"嘿嘿，看來我的實力也長進了不少呢。"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":{"char_id":"SPIRA_CORRUPT_NULL_DASH","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"너...... 잘도 내 앞에 다시 나타났구나.","JPN":"お前……よくもまた私の前に現れたな。","ENG":"You... You got some nerve showing up again.","TWN":"你……又是你。"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SPIRA_CORRUPT_NULL_DASH","text":{"KOREA":"리타 언니......? 왜, 왜 그렇게 무서운 표정이에요?","JPN":"リタお姉ちゃん……？　な、なんでそんなに怖い顔を？","ENG":"Rita? W-why do you look so scary?","TWN":"麗塔姐姐……？為、為什麼表情這麼可怕？"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":{"char_id":"SPIRA_CORRUPT_NULL_DASH","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SPIRA_CORRUPT_NULL_DASH","text":{"KOREA":"저 대시예요, 언니. 제 얼굴 잊어버린 거 아니죠?","JPN":"私はダッシュですよ。リタお姉ちゃん、私の顔を忘れちゃったんですか？","ENG":"It's me. Dash! You didn't forget my face, did you?","TWN":"我是黛西啊，姐姐。你不記得我了嗎？"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":{"char_id":"SPIRA_CORRUPT_NULL_DASH","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"RITA_HORIZON_NULL_ON","text":{"KOREA":"언니라고 부르지 마!","JPN":"軽々しく呼ぶな！","ENG":"Don't even try!","TWN":"別叫我姐姐！"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_ON","face":"UNIT_HATE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"RITA_HORIZON_NULL_ON","text":{"KOREA":"꼬맹이인 척 한다고 봐줄 생각 없어.","JPN":"ガキのふりをしても容赦はしない。","ENG":"I'm not going to cut you any slack, just because you pretend to be the kid.","TWN":"你即使裝成小鬼的樣子，我也不會手軟。"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"RITA_HORIZON_NULL_ON","text":{"KOREA":"이번에야말로...... 두 번 다시 내 앞에 나타날 수 없게 만들어 주지.","JPN":"今度こそ……二度と私の前に現れないようにしてやる。","ENG":"This time... I'll make sure you'll never come back again.","TWN":"這次……我要讓你再也不能出現在我面前。"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"리타 언니!","JPN":"リタお姉ちゃん！","ENG":"Rita!","TWN":"麗塔姐姐！"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"RITA_HORIZON_NULL_ON","text":{"KOREA":"......꼬맹이?","JPN":"……ガキ？","ENG":"... Kid?","TWN":"……小鬼？"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_ON","face":"UNIT_SURPRISE"},"R":null}}}]`);export{e as default};